// Payload sent by WF11: patient_code, name, phone (E.164), clinic_name, doctor_name,
// follow_up_required, follow_up_date, visit_date
const data = $input.first().json.body || $input.first().json;

const name           = String(data.name           || data.patient_name || '').trim();
const phone          = String(data.phone          || '').trim();
const patientCode    = String(data.patient_code   || '').trim();
const clinicName     = String(data.clinic_name    || 'our clinic').trim();
const doctorName     = String(data.doctor_name    || 'your doctor').trim();
const followUpRequired = String(data.follow_up_required || 'No').trim();
const followUpDate   = data.follow_up_date || null;

if (!phone || !/^\+[1-9]\d{6,14}$/.test(phone)) {
  return [{ json: { _skip: true, reason: `Invalid phone: ${phone}`, patientCode } }];
}
if (!name) {
  return [{ json: { _skip: true, reason: 'Empty patient name', patientCode } }];
}

let msg = `Hi ${name}! 👋 Welcome to ${clinicName}. Your visit with ${doctorName} has been recorded.\n\n`;

if (followUpRequired === 'Yes' && followUpDate) {
  const fuDisplay = new Date(followUpDate).toLocaleDateString('en-IN', {
    day: 'numeric', month: 'long', year: 'numeric'
  });
  msg += `Your follow-up is scheduled for *${fuDisplay}*. We will remind you closer to the date.\n\n`;
}

msg += `Reply *CONFIRM* to confirm or *CANCEL* to cancel. Take care! 💙`;

return [{
  json: {
    _skip:          false,
    _patient_name:  name,
    _phone:         phone,
    _patient_code:  patientCode,
    _to_phone:      'whatsapp:' + phone,
    _message_body:  msg,
    _message_type:  'welcome'
  }
}];
